import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as l,b as o}from"./app-291b7530.js";const t="/assets/image-20231215151421249-0793a100.png",a={},r=o('<h2 id="消息发送的流程" tabindex="-1"><a class="header-anchor" href="#消息发送的流程" aria-hidden="true">#</a> 消息发送的流程</h2><ol><li>生产者发送消息给MQ</li><li>MQ收到消息，将<strong>消息持久化存储</strong></li><li>返回ack给生产者</li><li>MQ发送消息给消费者</li><li>如果消费者成功消费，则删除掉持久化的消息</li></ol><figure><img src="'+t+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="存储方式" tabindex="-1"><a class="header-anchor" href="#存储方式" aria-hidden="true">#</a> 存储方式</h2><p><strong>MQ采用的是文件系统</strong>来进行存储的，磁盘如果使用得当，磁盘的速度完全可以匹配上网络的数据的传输速度，目前高性能的磁盘，顺序写的速度能达到600MB/s，超过了一般网卡的传输速度，但是磁盘的随机写只有大概100KB/s，和顺序写速度相差很大，RocketMQ采用顺序写，来保证消息的存储速度</p><blockquote><p>零拷贝技术</p></blockquote><p>操作系统分为<code>用户态</code>和<code>内核态</code>，文件操作，网络操作涉及到两种状态的切换，数据也在两种状态之间来回拷贝</p><p>传统IO中，一台服务器将本机的文件通过网络发送出去，通常需要两个步骤：</p><ol><li>read读取本地文件</li><li>write将内容通过网络发送出去</li></ol><p>看似简单的2个步骤，其实包含了4次拷贝：</p><ol><li>磁盘拷贝到内核态</li><li>内核态拷贝到用户态</li><li>用户态进行了一些操作之后，又拷贝到内核态</li><li>内核态拷贝到网卡进行发送</li></ol>',11),c=[r];function s(n,d){return e(),l("div",null,c)}const h=i(a,[["render",s],["__file","消息存储.html.vue"]]);export{h as default};
